#include <stdio.h>
#include <string.h>

int result(const char *a, const char *b){
    if(strcmp(a,b)==0) return 0; // tie
    // a beats b ? return 1 : -1
    if(strcmp(a,"Rock")==0){
        if(strcmp(b,"Scissors")==0 || strcmp(b,"Water")==0) return 1;
        else return -1; // b is Paper
    }
    if(strcmp(a,"Paper")==0){
        if(strcmp(b,"Rock")==0) return 1;
        else return -1; // b is Scissors or Water
    }
    if(strcmp(a,"Scissors")==0){
        if(strcmp(b,"Paper")==0) return 1;
        else return -1; // b is Rock or Water
    }
    if(strcmp(a,"Water")==0){
        if(strcmp(b,"Paper")==0 || strcmp(b,"Scissors")==0) return 1;
        else return -1; // b is Rock
    }
    return 0; // should never reach
}

int main(){
    int N; if(scanf("%d",&N)!=1) return 0;
    char you[20], comp[20];
    int youWins=0, compWins=0;
    for(int i=1;i<=N;i++){
        scanf("%s %s",you,comp);
        int r=result(you,comp);
        if(r==1){
            printf("Round %d: You\n",i);
            youWins++;
        }else if(r==-1){
            printf("Round %d: Computer\n",i);
            compWins++;
        }else{
            printf("Round %d: Tie\n",i);
        }
    }
    if(youWins>compWins) printf("You won the overall match\n");
    else if(compWins>youWins) printf("Computer won the overall match\n");
    else printf("Match tied\n");
    return 0;
}

