code.Java:
import java.io.*;
import java.util.*;

public class Main {
    private static int result(String a, String b){
        if(a.equals(b)) return 0;
        switch(a){
            case "Rock": return (b.equals("Scissors")||b.equals("Water"))?1:-1;
            case "Paper": return b.equals("Rock")?1:-1;
            case "Scissors": return b.equals("Paper")?1:-1;
            case "Water": return (b.equals("Paper")||b.equals("Scissors"))?1:-1;
        }
        return 0;
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String line = br.readLine();
        if(line==null||line.isEmpty()) return;
        int N = Integer.parseInt(line.trim());
        int youWins=0, compWins=0;
        StringBuilder out = new StringBuilder();
        for(int i=1;i<=N;i++){
            StringTokenizer st = new StringTokenizer(br.readLine());
            String you = st.nextToken();
            String comp = st.nextToken();
            int r = result(you, comp);
            if(r==1){ out.append("Round ").append(i).append(": You\n"); youWins++; }
            else if(r==-1){ out.append("Round ").append(i).append(": Computer\n"); compWins++; }
            else{ out.append("Round ").append(i).append(": Tie\n"); }
        }
        if(youWins>compWins) out.append("You won the overall match\n");
        else if(compWins>youWins) out.append("Computer won the overall match\n");
        else out.append("Match tied\n");
        System.out.print(out.toString());
    }
}

