import sys

def result(a,b):
    if a==b:
        return 0
    if a=='Rock':
        return 1 if b in ('Scissors','Water') else -1
    if a=='Paper':
        return 1 if b=='Rock' else -1
    if a=='Scissors':
        return 1 if b=='Paper' else -1
    if a=='Water':
        return 1 if b in ('Paper','Scissors') else -1
    return 0

def main():
    data=sys.stdin.read().strip().splitlines()
    if not data:
        return
    n=int(data[0])
    you_wins=comp_wins=0
    out=[]
    for i in range(1,n+1):
        you,comp=data[i].split()
        r=result(you,comp)
        if r==1:
            out.append(f"Round {i}: You")
            you_wins+=1
        elif r==-1:
            out.append(f"Round {i}: Computer")
            comp_wins+=1
        else:
            out.append(f"Round {i}: Tie")
    if you_wins>comp_wins:
        out.append("You won the overall match")
    elif comp_wins>you_wins:
        out.append("Computer won the overall match")
    else:
        out.append("Match tied")
    sys.stdout.write("\n".join(out))

if __name__=="__main__":
    main()

